                <div className="border-t border-gray-100 px-5 py-3">
                  <p className="text-xs font-medium text-gray-400">
                    Latest summary &middot;{" "}
                    {latest.createdAt.toLocaleDateString()} &middot;{" "}
                    {latest.messageCount} messages
