type Column = {
  name: string;
  type: string;
  pk?: boolean;
  nullable?: boolean;
  unique?: boolean;
  default?: string;
  fk?: string;
  note?: string;
};

function Badge({ children, color }: { children: React.ReactNode; color: string }) {
  return (
    <span className={`rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase ${color}`}>
      {children}
    </span>
  );
}

function TableCard({ name, description, columns, indexes }: {
  name: string;
  description: string;
  columns: Column[];
  indexes: string[];
}) {
  return (
    <div id={name} className="rounded-lg border border-gray-200 bg-white scroll-mt-6">
      <div className="border-b border-gray-100 px-5 py-4">
        <h2 className="font-mono text-base font-semibold text-gray-900">{name}</h2>
        <p className="mt-1 text-sm text-gray-500">{description}</p>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left text-sm">
          <thead className="border-b border-gray-100 bg-gray-50 text-xs uppercase tracking-wide text-gray-400">
            <tr>
              <th className="px-5 py-2">Column</th>
              <th className="px-5 py-2">Type</th>
              <th className="px-5 py-2">Constraints</th>
              <th className="px-5 py-2">Default</th>
              <th className="px-5 py-2">Notes</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {columns.map((col) => (
              <tr key={col.name} className="hover:bg-gray-50/50">
                <td className="px-5 py-2 font-mono text-xs font-medium text-gray-800">
                  {col.name}
                </td>
                <td className="px-5 py-2 font-mono text-xs text-gray-500">
                  {col.type}
                </td>
                <td className="space-x-1 px-5 py-2">
                  {col.pk && <Badge color="bg-violet-100 text-violet-700">PK</Badge>}
                  {col.nullable === false && !col.pk && (
                    <Badge color="bg-amber-100 text-amber-700">NOT NULL</Badge>
                  )}
                  {col.unique && <Badge color="bg-cyan-100 text-cyan-700">UNIQUE</Badge>}
                  {col.fk && (
                    <a
                      href={`#${col.fk.split(".")[0]}`}
                      className="inline-block rounded bg-blue-50 px-1.5 py-0.5 text-[10px] font-semibold uppercase text-blue-600 hover:bg-blue-100"
                    >
                      FK &rarr; {col.fk}
                    </a>
                  )}
                </td>
                <td className="px-5 py-2 font-mono text-xs text-gray-400">
                  {col.default ?? ""}
                </td>
                <td className="px-5 py-2 text-xs text-gray-400">{col.note ?? ""}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {indexes.length > 0 && (
        <div className="border-t border-gray-100 px-5 py-3">
          <p className="mb-1.5 text-[10px] font-semibold uppercase tracking-wide text-gray-400">
            Indexes
          </p>
          <ul className="space-y-0.5">
            {indexes.map((idx) => (
              <li key={idx} className="font-mono text-xs text-gray-500">
                {idx}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default function SchemaPage() {
  return (
    <main className="mx-auto max-w-5xl px-6 py-10">
      <div className="mb-8">
        <h1 className="text-2xl font-semibold">Database Schema</h1>
        <p className="mt-1 text-sm text-gray-500">
          PostgreSQL (Neon) &middot; ORM: Drizzle &middot; All PKs are UUID v4
          &middot; All timestamps are <code className="text-xs">timestamptz</code>
        </p>
      </div>

      {/* Quick nav */}
      <div className="mb-8 flex flex-wrap gap-2">
        {tables.map((t) => (
          <a
            key={t.name}
            href={`#${t.name}`}
            className="rounded-md border border-gray-200 bg-white px-3 py-1.5 font-mono text-xs text-gray-600 hover:border-gray-300 hover:bg-gray-50"
          >
            {t.name}
          </a>
        ))}
      </div>

      {/* Tables */}
      <div className="space-y-6">
        {tables.map((t) => (
          <TableCard key={t.name} {...t} />
        ))}
      </div>

      {/* Relations */}
      <div className="mt-10">
        <h2 className="mb-4 text-lg font-semibold">Foreign Key Relations</h2>
        <div className="overflow-hidden rounded-lg border border-gray-200 bg-white">
          <table className="w-full text-left text-sm">
            <thead className="border-b border-gray-100 bg-gray-50 text-xs uppercase tracking-wide text-gray-400">
              <tr>
                <th className="px-5 py-2">From</th>
                <th className="px-5 py-2"></th>
                <th className="px-5 py-2">To</th>
                <th className="px-5 py-2">On Delete</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {relations.map((r) => (
                <tr key={r.from} className="hover:bg-gray-50/50">
                  <td className="px-5 py-2 font-mono text-xs">{r.from}</td>
                  <td className="px-5 py-2 text-gray-300">&rarr;</td>
                  <td className="px-5 py-2 font-mono text-xs">{r.to}</td>
                  <td className="px-5 py-2">
                    <Badge color="bg-red-50 text-red-500">{r.onDelete}</Badge>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </main>
  );
}

